const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const router = express.Router();

const auth = require('../middleware/auth');

const {saveFile,deleteFile} = require('../utils/storage');


const upload = multer();

const optimize = async (file)=>{
    let buffer = file.buffer;

    if(file.mimetype === 'image/png'){
        return sharp(buffer).png({quality: 70}).toBuffer();
    }

    return sharp(buffer).jpeg({quality: 70}).toBuffer();
};

router.post('/upload',upload.single('file'),async (req,res)=>{
    try{
        const buffer = await optimize(req.file);
        const filename = Date.now() + '-' + req.file.originalname;
        const folder = req.body.folder || '';
        const result = await saveFile(buffer,filename,folder);

        res.json(result);

    }catch(error){
        res.status(500).json({error: error.message});
    }
});

router.delete('/delete/:folder/:id',(req,res)=>{
    
    try{

        const id = req.params.id;
        const folder = req.params.folder;

        const public_id = `${folder}/${id}`;

        // console.log(public_id);

        deleteFile(public_id);

        res.json({message: 'Deleted'});

    }catch(error){
        res.status(500).json({
            error: error.message
        })
    }
});

module.exports = router;
